import sys, json
from collections import defaultdict
d = json.load(sys.stdin)
by_user = defaultdict(list)
for o in d:
    by_user[o['user_id']].append(o)
for uid, orders in by_user.items():
    if len(orders) >= 2:
        print(f'User {uid} has {len(orders)} orders:')
        for o in orders:
            print(f'  {o[\"id\"]}: {o[\"total_cents\"]} {o[\"currency\"]} status={o[\"status\"]} created={o[\"created_at\"]}')
\""

